changeSet.sql:
drop trigger if exists trg_pub_enforce_resource_id_immutable on gmdb.pub;
create trigger trg_pub_enforce_resource_id_immutable
    before update of details on gmdb.pub
    for each row
    execute function gmdb.details_enforce_resource_id_immutable();

drop trigger if exists trg_pub_default_resource_id on gmdb.pub;
create trigger trg_pub_default_resource_id
    before insert on gmdb.pub
    for each row
    execute function gmdb.details_default_resource_id();
